record.field:
services:
  app:
    user: 0:0
    image: etherpad/etherpad:latest
    tty: true
    stdin_open: true
    volumes:
    - ../files/plugins:/opt/etherpad-lite/src/plugin_packages
    - ../files/etherpad_var:/opt/etherpad-lite/var
    depends_on:
    - postgres
    environment:
      NODE_ENV: {{ node_env }}
      ADMIN_PASSWORD: {{ admin_password }}
      DB_CHARSET: {{ db_charset }}
      DB_HOST: {{ db_host }}
      DB_NAME: {{ db_name }}
      DB_PASS: {{ db_pass }}
      DB_PORT: {{ db_port }}
      DB_TYPE: {{ db_type }}
      DB_USER: {{ db_user }}
      DEFAULT_PAD_TEXT: {{ default_pad_text }}
      DISABLE_IP_LOGGING: {{ disable_ip_logging }}
      SOFFICE: {{ soffice }}
      TRUST_PROXY: {{ trust_proxy }}
    restart: always
    expose:
    - 9001
    container_name: '{{ INSTANCE_CODE }}'
    ports:
    - '{{ PORT_HTTP }}:9001'
    networks:
    - internal
    - agz-proxy-network
  postgres:
    image: postgres:15-alpine
    environment:
      POSTGRES_DB: {{ postgres_db }}
      POSTGRES_PASSWORD: {{ postgres_password }}
      POSTGRES_USER: {{ postgres_user }}
      PGDATA: /var/lib/postgresql/data/pgdata
    restart: always
    volumes:
    - ../files/postgres_data:/var/lib/postgresql/data/pgdata
    container_name: '{{ INSTANCE_CODE }}_postgres'
    networks:
    - internal
networks:
  internal:
    driver: bridge
  agz-proxy-network:
    external: true
